import React, { useState, useEffect, useRef } from "react";

export default function FitnessMoodAsset() {
  // Weekly goal in km (or units)
  const [goal, setGoal] = useState(() => {
    const saved = localStorage.getItem("fitness_goal_km");
    return saved ? Number(saved) : 20;
  });

  // Map of date (YYYY-MM-DD) -> km
  const [runs, setRuns] = useState(() => {
    try {
      const raw = localStorage.getItem("fitness_runs_map");
      return raw ? JSON.parse(raw) : {};
    } catch {
      return {};
    }
  });

  // Quick add input
  const [addKm, setAddKm] = useState("");

  // Journal
  const [journal, setJournal] = useState(() => {
    return localStorage.getItem("fitness_journal") || "";
  });

  // Quick habits
  const initialHabits = [
    { id: 1, label: "Run / Walk", key: "habit_run" },
    { id: 2, label: "Hydration 2L+", key: "habit_water" },
    { id: 3, label: "Sleep 7-8h", key: "habit_sleep" },
  ];
  const [habits, setHabits] = useState(() => {
    try {
      const raw = localStorage.getItem("fitness_habits");
      if (raw) return JSON.parse(raw);
    } catch {}
    // initialize from defaults as unchecked
    return initialHabits.map((h) => ({ ...h, done: false }));
  });

  // floating confetti trigger for milestone
  const [celebrate, setCelebrate] = useState(false);

  // refs for animation timing
  const celebrateTimeout = useRef(null);

  useEffect(() => {
    localStorage.setItem("fitness_goal_km", String(goal));
  }, [goal]);

  useEffect(() => {
    localStorage.setItem("fitness_runs_map", JSON.stringify(runs));
  }, [runs]);

  useEffect(() => {
    localStorage.setItem("fitness_journal", journal);
  }, [journal]);

  useEffect(() => {
    localStorage.setItem("fitness_habits", JSON.stringify(habits));
  }, [habits]);

  // Helpers to format dates
  const todayKey = (d = new Date()) => d.toISOString().slice(0, 10);

  const lastNDates = (n = 7) => {
    const arr = [];
    for (let i = n - 1; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      arr.push(d);
    }
    return arr;
  };

  // Weekly values for the last 7 days
  const weekDates = lastNDates(7);
  const weekValues = weekDates.map((d) => runs[d.toISOString().slice(0, 10)] || 0);
  const totalThisWeek = weekValues.reduce((s, v) => s + v, 0);
  const progressPct = Math.min(100, Math.round((totalThisWeek / Math.max(1, goal)) * 100));

  // Add run for today
  const handleAddRun = (e) => {
    e?.preventDefault();
    const km = parseFloat(addKm);
    if (Number.isNaN(km) || km <= 0) return;
    const key = todayKey();
    setRuns((prev) => {
      const next = { ...prev, [key]: (prev[key] || 0) + Number(km) };
      return next;
    });
    setAddKm("");
    // celebrate if crossing milestone (>= goal)
    const newTotal = totalThisWeek + km;
    if (newTotal >= goal && totalThisWeek < goal) {
      setCelebrate(true);
      clearTimeout(celebrateTimeout.current);
      celebrateTimeout.current = setTimeout(() => setCelebrate(false), 3500);
    }
  };

  // Toggle habit
  const toggleHabit = (id) => {
    setHabits((h) => h.map((item) => (item.id === id ? { ...item, done: !item.done } : item)));
  };

  // Reset week (quick action)
  const resetWeek = () => {
    const newRuns = { ...runs };
    weekDates.forEach((d) => {
      const key = d.toISOString().slice(0, 10);
      delete newRuns[key];
    });
    setRuns(newRuns);
  };

  // SVG circular progress calculations
  const radius = 36;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (progressPct / 100) * circumference;

  // small accessibility helper for keyboard add
  const addInputRef = useRef(null);

  return (
    <div className="w-full h-full p-6 bg-gradient-to-br from-emerald-50 via-emerald-100 to-white rounded-2xl shadow-inner overflow-hidden flex flex-col">
      <header className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-3">
          <div className="relative">
            <div className="w-14 h-14 rounded-full bg-emerald-600 flex items-center justify-center text-white text-2xl shadow-lg transform transition-transform duration-500 hover:scale-105">
              🏃‍♀️
            </div>
            {celebrate && (
              <div className="absolute -top-2 -right-2 flex space-x-1">
                <span className="text-sm animate-bounce text-yellow-400">✨</span>
                <span className="text-sm animate-bounce text-pink-400">🎉</span>
              </div>
            )}
          </div>
          <div>
            <h1 className="text-2xl font-semibold text-emerald-800 leading-tight">Daily Fitness Planner</h1>
            <p className="text-sm text-emerald-600">Set clear goals • Track runs • Reflect daily</p>
          </div>
        </div>

        <div className="flex items-center space-x-3">
          <div className="text-right">
            <p className="text-xs text-emerald-500">Weekly goal</p>
            <div className="flex items-baseline space-x-2">
              <input
                aria-label="Weekly goal in kilometers"
                type="number"
                min="1"
                value={goal}
                onChange={(e) => setGoal(Math.max(1, Number(e.target.value || 0)))}
                className="w-20 bg-white text-emerald-800 font-semibold px-2 py-1 rounded-md border border-emerald-200 shadow-sm focus:outline-none focus:ring-2 focus:ring-emerald-300"
              />
              <span className="text-xs text-emerald-600">km / week</span>
            </div>
          </div>

          <div className="w-20 h-20 flex items-center justify-center">
            <svg className="w-20 h-20 transform -rotate-90" viewBox="0 0 80 80">
              <defs>
                <linearGradient id="g1" x1="0" x2="1">
                  <stop offset="0%" stopColor="#059669" />
                  <stop offset="100%" stopColor="#10B981" />
                </linearGradient>
              </defs>
              <g>
                <circle cx="40" cy="40" r={radius} stroke="#E6F4EE" strokeWidth="8" fill="none" />
                <circle
                  cx="40"
                  cy="40"
                  r={radius}
                  stroke="url(#g1)"
                  strokeWidth="8"
                  strokeLinecap="round"
                  fill="none"
                  strokeDasharray={circumference}
                  strokeDashoffset={strokeDashoffset}
                  style={{ transition: "stroke-dashoffset 700ms cubic-bezier(.2,.9,.2,1)" }}
                />
                <text x="40" y="45" textAnchor="middle" className="text-sm" style={{ fontSize: 12, fill: "#065f46", fontWeight: 700 }}>
                  {progressPct}%
                </text>
              </g>
            </svg>
          </div>
        </div>
      </header>

      <main className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Left: Chart + summary */}
        <section className="col-span-2 bg-white rounded-xl p-4 shadow-sm flex flex-col">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-lg font-medium text-emerald-700 flex items-center space-x-2">
              <span>Weekly Activity</span>
              <span className="text-xs bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full">last 7 days</span>
            </h2>
            <div className="text-sm text-emerald-600">
              <div>Total: <span className="font-semibold text-emerald-800">{totalThisWeek} km</span></div>
              <div className="text-xs">Goal: {goal} km</div>
            </div>
          </div>

          <div className="flex-1 flex flex-col md:flex-row md:items-end md:justify-between">
            {/* Bars */}
            <div className="flex-1 flex items-end space-x-2 px-2 py-3">
              {weekValues.map((v, idx) => {
                const max = Math.max(...weekValues, goal / 7, 1);
                const heightPct = Math.min(100, Math.round((v / max) * 100));
                const day = weekDates[idx].toLocaleDateString(undefined, { weekday: "short" }).slice(0, 3);
                return (
                  <div key={idx} className="flex-1 flex flex-col items-center">
                    <div
                      className="w-full bg-emerald-100 rounded-t-md relative overflow-hidden transition-all duration-500"
                      style={{ height: `${Math.max(8, Math.round((heightPct / 100) * 160))}px` }}
                      title={`${day}: ${v} km`}
                    >
                      <div className="absolute -top-6 left-1/2 transform -translate-x-1/2 text-xs text-emerald-700 font-medium">
                        {v > 0 ? `${v} km` : ""}
                      </div>
                    </div>
                    <div className="mt-2 text-xs text-emerald-500">{day}</div>
                  </div>
                );
              })}
            </div>

            {/* Quick add / actions */}
            <div className="mt-4 md:mt-0 md:ml-6 w-full md:w-56 bg-emerald-50 border border-emerald-100 rounded-lg p-3 shadow-inner">
              <form onSubmit={handleAddRun} className="flex flex-col space-y-2">
                <label className="text-xs text-emerald-600 font-medium">Quick Add Run</label>
                <div className="flex items-center space-x-2">
                  <input
                    ref={addInputRef}
                    aria-label="Add kilometers"
                    type="number"
                    step="0.1"
                    min="0"
                    placeholder="e.g., 5.2"
                    value={addKm}
                    onChange={(e) => setAddKm(e.target.value)}
                    className="flex-1 px-2 py-2 rounded-md border border-emerald-200 focus:outline-none focus:ring-2 focus:ring-emerald-300 bg-white"
                  />
                  <button
                    type="submit"
                    onClick={handleAddRun}
                    className="bg-emerald-600 text-white px-3 py-2 rounded-md hover:bg-emerald-500 transform transition duration-200 active:scale-95 flex items-center space-x-2"
                  >
                    <span className="text-lg">➕</span>
                    <span className="text-sm font-medium">Add</span>
                  </button>
                </div>
                <div className="flex items-center justify-between text-xs text-emerald-500">
                  <button
                    type="button"
                    onClick={() => {
                      setAddKm("1");
                      addInputRef.current?.focus();
                    }}
                    className="px-2 py-1 rounded-md hover:bg-emerald-100"
                  >
                    +1 km
                  </button>
                  <button
                    type="button"
                    onClick={() => resetWeek()}
                    className="px-2 py-1 rounded-md text-rose-600 hover:bg-rose-50"
                    title="Clear this week's entries"
                  >
                    Reset week
                  </button>
                </div>
              </form>
            </div>
          </div>
        </section>

        {/* Right: Journal + Habits */}
        <aside className="col-span-1 flex flex-col space-y-4">
          <div className="bg-white rounded-xl p-3 shadow-sm flex flex-col">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm font-medium text-emerald-700">Journal ✍️</h3>
              <p className="text-xs text-emerald-500">{new Date().toLocaleDateString()}</p>
            </div>
            <textarea
              placeholder="Reflect on today's run or set a mini intention..."
              value={journal}
              onChange={(e) => setJournal(e.target.value)}
              className="w-full min-h-[120px] resize-none p-2 border border-emerald-100 rounded-md focus:outline-none focus:ring-2 focus:ring-emerald-200"
            />
            <div className="mt-2 flex items-center justify-between">
              <div className="text-xs text-emerald-500">
                {journal.length} chars
              </div>
              <div className="flex items-center space-x-2">
                <button
                  onClick={() => {
                    setJournal("");
                  }}
                  className="text-xs px-2 py-1 rounded-md hover:bg-emerald-50 text-rose-600"
                >
                  Clear
                </button>
                <button
                  onClick={() => {
                    // small pulse animation
                    setCelebrate(true);
                    clearTimeout(celebrateTimeout.current);
                    celebrateTimeout.current = setTimeout(() => setCelebrate(false), 900);
                  }}
                  className="bg-emerald-600 text-white text-xs px-3 py-1 rounded-md hover:bg-emerald-500"
                >
                  Save Note
                </button>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl p-3 shadow-sm">
            <h4 className="text-sm font-medium text-emerald-700 mb-2">Today's Habits</h4>
            <ul className="space-y-2">
              {habits.map((h) => (
                <li key={h.id} className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <button
                      onClick={() => toggleHabit(h.id)}
                      className={`w-9 h-9 flex items-center justify-center rounded-md transition ${
                        h.done ? "bg-emerald-600 text-white" : "bg-emerald-50 text-emerald-600 border border-emerald-100"
                      }`}
                      aria-pressed={h.done}
                    >
                      {h.done ? "✓" : "○"}
                    </button>
                    <span className={`text-sm ${h.done ? "line-through text-emerald-400" : "text-emerald-700"}`}>{h.label}</span>
                  </div>
                  <div className="text-xs text-emerald-500">{h.done ? "Done" : "Tap"}</div>
                </li>
              ))}
            </ul>
            <div className="mt-3 text-xs text-emerald-500">
              Small wins add up — toggle a habit to celebrate momentum.
            </div>
          </div>
        </aside>
      </main>

      <footer className="mt-4 flex items-center justify-between text-xs text-emerald-600">
        <div className="flex items-center space-x-3">
          <span className="px-2 py-1 bg-emerald-50 rounded-md">✨ Keep it consistent</span>
          <span className="px-2 py-1 bg-emerald-50 rounded-md">🧭 Plan • Do • Reflect</span>
        </div>
        <div className="flex items-center space-x-3">
          <div className="text-emerald-500">Need a nudge? Try a 10-min run today</div>
          <button
            onClick={() => {
              // add small 1 km as nudge
              setRuns((prev) => {
                const key = todayKey();
                const next = { ...prev, [key]: (prev[key] || 0) + 1 };
                return next;
              });
              setCelebrate(true);
              clearTimeout(celebrateTimeout.current);
              celebrateTimeout.current = setTimeout(() => setCelebrate(false), 1600);
            }}
            className="bg-emerald-600 text-white px-3 py-1 rounded-md hover:bg-emerald-500"
          >
            Nudge +1 km
          </button>
        </div>
      </footer>
    </div>
  );
}

